sql:
SELECT COUNT(*) AS NumberOfIncidentsReportedByAnalysts
FROM incident_reports
WHERE user_id IN (SELECT user_id FROM users WHERE role = 'analyst');

external_knowledge:
- 'Capturing the suspects' refers to cases that were resolved with an arrest;
- 'Law enforcement personnel' indicates officers from the police force;
- 'Badge details' corresponds to the unique badge numbers of the officers;
- 'Cases' are incidents reported and documented in the system;
- Officers involved in these cases must have non-null badge numbers for identification purposes.

sql:
SELECT AVG(incident_time) AS AverageIncidentTime
FROM incidents
WHERE resolution = 'ARREST';

SELECT *
FROM incidents
WHERE district = 'SOUTHERN';

SELECT DISTINCT i.category
FROM incidents i
WHERE i.resolution != '0';

SELECT incidents.district, categories.category_name
FROM incidents
INNER JOIN categories ON incidents.category = categories.category_name;

SELECT *
FROM districts
WHERE district_id > 0;
